function solve(s) {
    // Step 1: Calculate Frequencies
    const freq = new Map();
    for (const char of s) {
        freq.set(char, (freq.get(char) || 0) + 1);
    }

    // Step 2: Define Mirror Mapping Function
    const getMirror = (c) => {
        const code = c.charCodeAt(0);

        // Check for lowercase letters ('a' = 97, 'z' = 122)
        if (code >= 97 && code <= 122) {
            // a maps to z, b maps to y, etc.
            // Index of c from 'a' is (code - 97)
            // Mirror index from 'a' is 25 - (code - 97)
            const mirrorCode = 97 + (25 - (code - 97));
            return String.fromCharCode(mirrorCode);
        }

        // Check for digits ('0' = 48, '9' = 57)
        if (code >= 48 && code <= 57) {
            // 0 maps to 9, 1 maps to 8, etc.
            // Digit value is (code - 48)
            // Mirror value is 9 - (code - 48)
            const mirrorValue = 9 - (code - 48);
            return String.fromCharCode(mirrorValue + 48);
        }

        // Should not happen based on constraints
        return null;
    };

    let totalDifference = 0;
    const processedPairs = new Set();

    // Step 3 & 4: Iterate over unique characters and calculate sum
    for (const c of freq.keys()) {
        const m = getMirror(c);

        if (!m) continue; // Should not happen

        // Create canonical pair identifier (lexicographically sorted)
        const pairKey = c < m ? `${c}|${m}` : `${m}|${c}`;

        if (processedPairs.has(pairKey)) {
            continue;
        }

        // Mark pair as processed
        processedPairs.add(pairKey);

        // Get frequencies, defaulting to 0 if the mirror character is not in s
        const freqC = freq.get(c) || 0;
        const freqM = freq.get(m) || 0;

        // Calculate absolute difference and add to sum
        const difference = Math.abs(freqC - freqM);
        totalDifference += difference;
    }

    return totalDifference;
}

