	// Step 1: Calculate Frequencies
	freq := make(map[rune]int)
	for _, c := range s {
		freq[c]++
	}

	// Helper function to get the mirror character
	getMirror := func(c rune) (rune, bool) {
		if c >= 'a' && c <= 'z' {
			// Lowercase letters: 'a' <-> 'z', 'b' <-> 'y', etc.
			// The mirror character is 'a' + ('z' - c)
			return 'a' + ('z' - c), true
		}
		if c >= '0' && c <= '9' {
			// Digits: '0' <-> '9', '1' <-> '8', etc.
			// The mirror character is '0' + ('9' - c)
			return '0' + ('9' - c), true
		}
		return 0, false
	}

	var totalDifference int64 = 0

	// Step 2: Iterate over unique characters and calculate sum
	// We iterate over the map keys and only process a pair (c, m) if c < m
	// to ensure each pair is counted exactly once.
	for c := range freq {
		m, ok := getMirror(c)
		if !ok {
			continue // Should not happen based on constraints
		}

		// Enforce canonical order: only process if c is lexicographically smaller than m
		if c >= m {
			continue
		}

		// Get frequencies
		freqC := int64(freq[c])
		// Use 0 if the mirror character m is not present in the string
		freqM := int64(freq[m])

		// Calculate absolute difference and add to sum
		diff := freqC - freqM
		if diff < 0 {
			diff = -diff
		}
		totalDifference += diff
	}

	return totalDifference
}

