			// Index of r from 'a' is (r - 'a')
			// Mirror index is 25 - (r - 'a')
			mirrorIndex := 25 - (r - 'a')
			return 'a' + mirrorIndex
		} else if r >= '0' && r <= '9' {
			// Digit mapping: '0' <-> '9', '1' <-> '8', etc.
			// Value of r is (r - '0')
			// Mirror value is 9 - (r - '0')
			mirrorValue := 9 - (r - '0')
			return '0' + rune(mirrorValue)
		}
		return 0 // Should not happen based on constraints
	}

	var totalDifference int64 = 0

	// We iterate over all unique characters c present in the string s.
	for c := range freq {
		m := getMirror(c)

		// To ensure each pair {c, m} is processed only once,
		// we only process it if c is lexicographically less than or equal to m.
		// This handles (c, m) where c < m, and the self-mirrored case (c == m).
		if c > m {
